// Fallback: gemini-flash-lite-latest (Widest availability for all API key tiers)
const PRIMARY_MODEL = "gemini-3-flash-preview";
const PRO_MODEL = "gemini-3-pro-preview";
const STABLE_MODEL = "gemini-flash-lite-latest";

const handleApiError = (error: any, action: string) => {
    console.error(`Neural Link Failure [${action}]:`, error);
    const message = error?.message || "Unknown protocol interference.";

    if (message.includes('400') || message.includes('INVALID_ARGUMENT')) {
        throw new Error(`Neural mismatch (400). The model '${PRIMARY_MODEL}' may not be available for your API key's tier or region yet.`);
    }

    throw new Error(`Neural processing failed: ${message}`);
};

/**
 * Utility to perform AI generation with automatic fallback if the specific model 
 * requested is not available for the user's API key tier.
 */
async function generateWithFallback(contents: any, schema: any, modelName: string = PRIMARY_MODEL): Promise<string> {
    const config = {
        responseMimeType: "application/json",
        responseSchema: schema
    };

    try {
        const response = await ai.models.generateContent({
            model: modelName,
            contents,
            config
        });
        // Accessing .text property directly as per latest SDK guidelines
        return response.text || "";
    } catch (error: any) {
        // If 404 (Not Found) or 400 (Invalid model for this key), try the stable fallback
        if (error?.message?.includes('404') || error?.message?.includes('400') || error?.message?.includes('not found')) {
            console.warn(`Model ${modelName} unavailable. Falling back to stability protocol...`);
            const fallbackResponse = await ai.models.generateContent({
                model: STABLE_MODEL,
