                    <span className="bg-red-500 text-white text-[10px] font-black px-1.5 py-0.5 rounded-md min-w-[20px] text-center animate-pulse">
                        {activeBugsCount}
                    </span>
                </div>
            ) : !['bugs', 'sprints'].includes(projectView) ? (
              <Filters
