  // Modals
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isCreateProjectOpen, setIsCreateProjectOpen] = useState(false);
  const [isCreateTaskOpen, setIsCreateTaskOpen] = useState(false);
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [isManageMembersOpen, setIsManageMembersOpen] = useState(false);
  const [memberProjectId, setMemberProjectId] = useState<string | null>(null);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);
  const [shareProject, setShareProject] = useState<Project | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [isVoiceOpen, setIsVoiceOpen] = useState(false);
  const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
  const [confirmation, setConfirmation] = useState<{ title: string; message: React.ReactNode; onConfirm: () => void; confirmText: string } | null>(null);

  useEffect(() => {
    api.auth.getSession().then(({ data: { session } }) => setSession(session));
    const { data: { subscription } } = api.auth.onAuthStateChange((_event, session) => setSession(session));
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session?.user) {
      api.auth.getUserProfile(session.user.id).then(profile => {
        if (profile) setCurrentUser(profile);
        else api.auth.createUserProfile(session.user).then(setCurrentUser);
      });
    } else {
      setCurrentUser(null);
    }
  }, [session]);

  // Listen for link failure
  useEffect(() => {
    const handleLost = () => {
      setFeatureFlags({ ai: false, voice: false });
      localStorage.setItem('aiFeaturesEnabled', 'false');
    };
    window.addEventListener('neural-link-lost', handleLost);
    return () => window.removeEventListener('neural-link-lost', handleLost);
  }, []);

  const confirm = (options: { title: string; message: React.ReactNode; onConfirm: () => void; confirmText?: string }) => {
    setConfirmation({ ...options, confirmText: options.confirmText || 'Confirm', onConfirm: () => { options.onConfirm(); setConfirmation(null); } });
  };

  const handleVoiceCommand = async (command: string) => {
    try {
      const result = await interpretVoiceCommand(command, { currentView, activeProjectId });
      return `Executed: ${result.action}`;
    } catch (e) {
      return "Neural link failed to interpret command.";
    }
  };

  if (!session || !currentUser) return <LandingPage onShowPrivacy={() => {}} />;
  if (loading) return <div className="min-h-screen bg-[#1C2326] flex items-center justify-center font-mono text-emerald-500 uppercase tracking-widest text-xs animate-pulse">Initializing Neural Mesh...</div>;

  const project = activeProjectId ? state.projects[activeProjectId] : null;

  return (
    <ConfirmationContext.Provider value={{ confirm }}>
      <div className="min-h-screen bg-[#1C2326] text-gray-100 flex flex-col font-sans selection:bg-emerald-500/30">

        {/* TOP NAVIGATION */}
        <nav className="h-16 border-b border-white/5 bg-[#131C1B]/80 backdrop-blur-xl sticky top-0 z-30 px-6 grid grid-cols-3 items-center">
          {/* LEFT: Branding & Active Project */}
          <div className="flex items-center gap-4">
            <button onClick={() => {setActiveProjectId(null); setCurrentView('dashboard');}} className="flex items-center gap-2.5 group flex-shrink-0">
              <AppLogo className="w-8 h-8 group-hover:scale-110 transition-transform" />
              <span className="font-black text-sm tracking-tighter uppercase hidden lg:block">Graphynovus</span>
            </button>

            {project && (
              <>
                <div className="h-4 w-px bg-white/10 mx-2" />
                <div className="flex flex-col min-w-0">
                  <span className="text-[10px] font-black text-emerald-500/70 uppercase tracking-widest leading-none mb-1">Active Project</span>
                  <h1 className="text-xs font-bold text-white truncate max-w-[150px] sm:max-w-[200px] leading-none">{project.name}</h1>
                </div>
              </>
            )}
          </div>

          {/* CENTER: Navigation Tabs */}
          <div className="flex justify-center">
            <div className="flex items-center gap-1 p-1 bg-black/20 rounded-xl border border-white/5">
              <button onClick={() => {setActiveProjectId(null); setCurrentView('dashboard');}} className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${currentView === 'dashboard' && !activeProjectId ? 'bg-white text-black shadow-lg' : 'text-gray-500 hover:text-white'}`}>Nodes</button>
              <button onClick={() => {setActiveProjectId(null); setCurrentView('tasks');}} className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${currentView === 'tasks' ? 'bg-white text-black shadow-lg' : 'text-gray-500 hover:text-white'}`}>Tasks</button>
              <button onClick={() => {setActiveProjectId(null); setCurrentView('resources');}} className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${currentView === 'resources' ? 'bg-white text-black shadow-lg' : 'text-gray-500 hover:text-white'}`}>Mesh</button>
            </div>
          </div>

          {/* RIGHT: Actions */}
          <div className="flex items-center justify-end gap-3">
            {activeProjectId && (
              <button 
                onClick={() => setIsChatOpen(!isChatOpen)} 
                className={`p-2 rounded-xl transition-all ${isChatOpen ? 'bg-white text-black shadow-lg shadow-white/5' : 'bg-white/5 text-gray-400 hover:bg-white/10 hover:text-white'}`}
              >
                <MessageSquareIcon className="w-5 h-5" />
              </button>
            )}
            {featureFlags.ai && (
              <button onClick={() => setIsVoiceOpen(true)} className="p-2 rounded-xl bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 hover:bg-emerald-500/20 transition-all">
                <BotMessageSquareIcon className="w-4 h-4" />
              </button>
            )}
            <button onClick={() => setIsSearchOpen(true)} className="p-2 text-gray-500 hover:text-white transition-colors">
              <SearchIcon className="w-5 h-5" />
            </button>
            <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-gray-500 hover:text-white transition-colors">
              <SettingsIcon className="w-5 h-5" />
            </button>
            <button onClick={() => api.auth.signOut()} className="p-2 text-gray-500 hover:text-red-400 transition-colors">
              <LogOutIcon className="w-5 h-5" />
            </button>
          </div>
        </nav>

        {/* MAIN CONTENT */}
        <main className="flex-grow p-6 overflow-x-hidden custom-scrollbar">
          {activeProjectId && project ? (
            <KanbanBoard 
              project={project} currentUser={currentUser} users={Object.values(state.users)} onlineUsers={onlineUsers} aiFeaturesEnabled={featureFlags.ai}
              onDragEnd={(r) => onDragEnd(project.id, r)} updateTask={(t) => updateTask(project.id, t)} addSubtasks={(tid, sts) => addSubtasks(project.id, tid, sts, currentUser.id)}
              addComment={(tid, text) => addComment(project.id, tid, text, currentUser)} addAiTask={(p) => addAiTask(project.id, p)}
              // FIX: Pass the addTask function from useAppState to KanbanBoard
              addTask={(td) => addTask(project.id, td, currentUser.id)} deleteTask={(tid, cid) => deleteTask(project.id, tid, cid)}
              addColumn={(t) => addColumn(project.id, t)} deleteColumn={(cid) => deleteColumn(project.id, cid)} isChatOpen={isChatOpen} onCloseChat={() => setIsChatOpen(false)} chatMessages={project.chatMessages}
              onSendMessage={(txt) => sendChatMessage(project.id, txt, currentUser)} onTaskClick={setSelectedTask} addProjectLink={(t, u) => addProjectLink(project.id, t, u, currentUser.id)}
              deleteProjectLink={deleteProjectLink} addBug={addBug} updateBug={updateBug} deleteBug={deleteBug} 
              addBugsBatch={(bugs) => addBugsBatch(project.id, bugs)} 
              deleteBugsBatch={deleteBugsBatch}
              addTasksBatch={(ts, sid) => addTasksBatch(project.id, ts, sid)} addSprint={(sd) => addSprint(project.id, sd)} updateSprint={(sid, up) => updateSprint(project.id, sid, up)}
              deleteSprint={(sid) => deleteSprint(project.id, sid)} bulkUpdateTaskSprint={bulkUpdateTaskSprint} completeSprint={completeSprint}
              addFilterSegment={(n, f) => addFilterSegment(project.id, n, f, currentUser.id)} updateFilterSegment={updateFilterSegment} deleteFilterSegment={deleteFilterSegment}
            />
          ) : currentView === 'dashboard' ? (
            <DashboardPage projects={Object.values(state.projects)} users={state.users} currentUser={currentUser} onlineUsers={onlineUsers} onSelectProject={setActiveProjectId} onCreateProject={() => setIsCreateProjectOpen(true)} onManageMembers={(id) => {setMemberProjectId(id); setIsManageMembersOpen(true);}} onShareProject={(p) => {setShareProject(p); setIsShareModalOpen(true);}} addProjectFromPlan={addProjectFromPlan} />
          ) : currentView === 'tasks' ? (
            <TasksPage projects={state.projects} users={state.users} currentUser={currentUser} onTaskClick={setSelectedTask} />
          ) : (
            <ResourceManagementPage projects={state.projects} users={state.users} onlineUsers={onlineUsers} onTaskClick={setSelectedTask} />
          )}
        </main>

        {/* MODALS & OVERLAYS */}
        <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} currentUser={currentUser} onUpdateUser={updateUserProfile} featureFlags={featureFlags} onFlagsChange={setFeatureFlags} projects={Object.values(state.projects)} onDeleteProject={deleteProject} onShowPrivacy={() => {}} />
        {isCreateProjectOpen && <CreateProjectModal onClose={() => setIsCreateProjectOpen(false)} onAddProject={(n, d) => addProject(n, d, currentUser.id)} />}
        {selectedTask && <TaskDetailsModal task={selectedTask} currentUser={currentUser} users={Object.values(state.users)} projectMembers={Object.values(state.users)} allProjectTags={[]} sprints={[]} onlineUsers={onlineUsers} onClose={() => setSelectedTask(null)} onUpdateTask={(t) => updateTask(activeProjectId!, t)} onAddSubtasks={(tid, sts) => addSubtasks(activeProjectId!, tid, sts, currentUser.id)} onAddComment={(tid, text) => addComment(activeProjectId!, tid, text, currentUser)} />}
        {isManageMembersOpen && memberProjectId && <ManageMembersModal project={state.projects[memberProjectId]} allUsers={Object.values(state.users)} onlineUsers={onlineUsers} onClose={() => setIsManageMembersOpen(false)} onSave={(mids) => updateProjectMembers(memberProjectId, mids)} />}
        {isShareModalOpen && shareProject && <ManageInviteLinksModal project={shareProject} currentUser={currentUser} onClose={() => setIsShareModalOpen(false)} />}
        <GlobalSearchModal isOpen={isSearchOpen} onClose={() => setIsSearchOpen(false)} projects={state.projects} users={state.users} onSelectProject={setActiveProjectId} onSelectTask={setSelectedTask} />
        <VoiceAssistantModal isOpen={isVoiceOpen} onClose={() => setIsVoiceOpen(false)} onCommand={handleVoiceCommand} />
        <FeedbackFab onClick={() => setIsFeedbackOpen(true)} />
        <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} onSubmit={async () => {}} />

        {/* CONFIRMATION OVERLAY */}
        {confirmation && (
          <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-[#131C1B] border border-gray-800 rounded-xl p-6 max-w-sm w-full shadow-2xl">
              <h2 className="text-white font-bold text-lg mb-2">{confirmation.title}</h2>
              <div className="text-gray-400 text-sm mb-6">{confirmation.message}</div>
              <div className="flex justify-end gap-3">
                <button onClick={() => setConfirmation(null)} className="px-4 py-2 text-gray-400 hover:text-white text-sm font-semibold">Cancel</button>
                <button onClick={confirmation.onConfirm} className="px-4 py-2 bg-red-600 text-white rounded-lg text-sm font-semibold hover:bg-red-700">{confirmation.confirmText}</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </ConfirmationContext.Provider>
  );
};

export default App;

import { useState, useEffect, useCallback } from 'react';
import { DropResult } from 'react-beautiful-dnd';
import { AppState, Task, NewTaskData, User, ChatMessage, AiGeneratedProjectPlan, Bug, TaskPriority, Subtask, AiGeneratedTaskFromFile, Sprint, FilterSegment, BugResponse } from '../types';
import { api } from '../services/api';
import { generateTaskFromPrompt } from '../services/geminiService';
import { Session } from '@supabase/supabase-js';
import { playSentSound } from '../utils/sound';

const initialState: AppState = {
  projects: {},
  users: {},
  projectOrder: [],
};

export const useAppState = (session: Session | null, currentUser: User | null, activeProjectId?: string | null) => {
  const [state, setState] = useState<AppState>(initialState);
  const [loading, setLoading] = useState(true);
  const userId = session?.user?.id;

  const fetchData = useCallback(async () => {
    if (!userId) {
      setState(initialState);
      setLoading(true);
      return;
    }
    setLoading(true);
    try {
        const freshState = await api.data.fetchInitialData(userId);
        const cacheKey = `gemini-board-cache-${userId}`;

        try {
            localStorage.setItem(cacheKey, JSON.stringify(freshState));
        } catch (e) {
            console.warn("Could not save state to cache:", e);
        }

        setState(freshState);
    } catch (error) {
        console.error("An error occurred while fetching app data:", error);
    } finally {
        setLoading(false);
    }
  }, [userId]);

  useEffect(() => {
    if (!userId) {
      setState(initialState);
      setLoading(true);
      return;
    }

    const cacheKey = `gemini-board-cache-${userId}`;
    const cachedStateJSON = localStorage.getItem(cacheKey);
    if (cachedStateJSON) {
      try {
        setState(JSON.parse(cachedStateJSON));
        setLoading(false); 
      } catch (e) {
        console.warn("Failed to parse cached state, clearing it.", e);
        localStorage.removeItem(cacheKey);
      }
    }

    fetchData();

  }, [userId, fetchData]);

  useEffect(() => {
    if (!activeProjectId || !session || !userId) return;
    const cacheKey = `gemini-board-cache-${userId}`;

    const handleNewMessage = (payload: any) => {
      const newMessageData = payload.new;

      setState(prevState => {
        const author = prevState.users[newMessageData.author_id];
        if (!author) return prevState;

        const project = prevState.projects[activeProjectId];
        if (!project) return prevState;

        const finalMessage: ChatMessage = {
            id: newMessageData.id,
            text: newMessageData.text,
            createdAt: newMessageData.created_at,
            author: author,
        };

        const isSender = author.id === userId;
        let newMessages;

        if (isSender) {
          const optimisticIndex = project.chatMessages.findIndex(m => m.id.startsWith('temp-') && m.text === finalMessage.text);
          if (optimisticIndex > -1) {
            newMessages = [...project.chatMessages];
            newMessages[optimisticIndex] = finalMessage;
          } else {
            if (project.chatMessages.some(m => m.id === finalMessage.id)) return prevState;
            newMessages = [...project.chatMessages, finalMessage];
          }
        } else {
          if (project.chatMessages.some(m => m.id === finalMessage.id)) return prevState;
          newMessages = [...project.chatMessages, finalMessage];
        }

        const updatedState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [activeProjectId]: {
                    ...project,
                    chatMessages: newMessages.sort((a,b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()),
                }
            }
        };
        localStorage.setItem(cacheKey, JSON.stringify(updatedState));
        return updatedState;
      });
    };

    const subscription = api.data.subscribeToProjectChat(activeProjectId, handleNewMessage);
    return () => { subscription.unsubscribe(); };
  }, [activeProjectId, session, userId]);


  const onDragEnd = useCallback(async (projectId: string, result: DropResult) => {
    const { destination, source, draggableId, type } = result;
    if (!destination || !currentUser || !userId) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const project = state.projects[projectId];
    if (!project) return;
    const cacheKey = `gemini-board-cache-${userId}`;

    if (type === 'column') {
        const newColumnOrder = Array.from(project.board.columnOrder) as string[];
        newColumnOrder.splice(source.index, 1);
        newColumnOrder.splice(destination.index, 0, draggableId);

        setState(prevState => {
            const updatedState = {
                ...prevState,
                projects: {
                    ...prevState.projects,
                    [projectId]: {
                        ...prevState.projects[projectId],
                        board: { ...prevState.projects[projectId].board, columnOrder: newColumnOrder }
                    }
                }
            };
            localStorage.setItem(cacheKey, JSON.stringify(updatedState));
            return updatedState;
        });

        try {
            await api.data.updateColumnOrder(projectId, newColumnOrder);
        } catch (error) {
            await fetchData();
        }
        return;
    }

    const startCol = project.board.columns[source.droppableId];
    const endCol = project.board.columns[destination.droppableId];
    if (!startCol || !endCol) return;

    const newStartTaskIds = Array.from(startCol.taskIds);
    newStartTaskIds.splice(source.index, 1);
    const newEndTaskIds = startCol.id === endCol.id ? newStartTaskIds : Array.from(endCol.taskIds);
    if (startCol.id !== endCol.id) {
        newEndTaskIds.splice(destination.index, 0, draggableId);
    } else {
        newStartTaskIds.splice(destination.index, 0, draggableId);
    }

    setState(prevState => {
      const updatedColumns = {
        ...prevState.projects[projectId].board.columns,
        [startCol.id]: { ...startCol, taskIds: newStartTaskIds },
        [endCol.id]: { ...endCol, taskIds: newEndTaskIds }
      };
      const updatedState = {
        ...prevState,
        projects: {
          ...prevState.projects,
          [projectId]: { ...prevState.projects[projectId], board: { ...prevState.projects[projectId].board, columns: updatedColumns } }
        }
      };
      localStorage.setItem(cacheKey, JSON.stringify(updatedState));
      return updatedState;
    });

    try {
        await api.data.moveTask(draggableId, destination.droppableId, destination.index + 1, currentUser.id);
    } catch (error) {
        await fetchData();
    }
  }, [state, currentUser, userId, fetchData]);

  const updateTask = useCallback(async (projectId: string, updatedTask: Task) => {
      if (!currentUser) return;
      await api.data.updateTask(updatedTask, currentUser.id, Object.values(state.users) as User[]);
      await fetchData();
  }, [fetchData, currentUser, state.users]);

  const addSubtasks = useCallback(async (projectId: string, taskId: string, newSubtasksData: Partial<Subtask>[], creatorId: string) => {
    await api.data.addSubtasks(taskId, newSubtasksData, creatorId);
    await fetchData();
  }, [fetchData]);


  const addComment = useCallback(async (projectId: string, taskId: string, commentText: string, author: User) => {
      await api.data.addComment(taskId, commentText, author.id);
      await fetchData();
  }, [fetchData]);

  const addTask = useCallback(async (projectId: string, taskData: NewTaskData, creatorId: string) => {
    const newTask = await api.data.addTask(taskData, creatorId);
    if (newTask && currentUser) {
      await api.data.moveTask(newTask.id, taskData.columnId, 1, currentUser.id);
    }
    await fetchData();
  }, [fetchData, currentUser]);

  const addTasksBatch = useCallback(async (projectId: string, tasksToCreate: AiGeneratedTaskFromFile[], sprintId: string | null) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
    if (!project) return;

    const columnMap = new Map<string, string>();
    for (const colId of project.board.columnOrder) {
        const col = project.board.columns[colId];
        if (col?.title) {
            columnMap.set(col.title.toLowerCase().trim(), col.id);
        }
    }

    const firstColumnId = project.board.columnOrder[0];

    const tasksData = tasksToCreate.map(task => {
        const statusKey = (task.status || '').toLowerCase().trim();
        return {
            title: task.title,
            description: task.description,
            priority: task.priority,
            column_id: columnMap.get(statusKey) || firstColumnId,
            creator_id: currentUser.id,
            sprint_id: sprintId, 
            tags: []
        };
    });

    if (tasksData.length > 0) {
        try {
            await api.data.addTasksBatch(tasksData);
            await fetchData();
        } catch (err) {
            console.error("Supabase Batch Transmission Failed:", err);
            alert("Neural mesh failed to transmit task array to database.");
        }
    }
  }, [fetchData, currentUser, state.projects]);

  const addAiTask = useCallback(async (projectId: string, prompt: string) => {
    if (!currentUser) throw new Error("User must be logged in to create a task.");
    const project = state.projects[projectId];
    if (!project || project.board.columnOrder.length === 0) throw new Error("Cannot add AI task to a project with no columns.");

    const generatedData = await generateTaskFromPrompt(prompt);
    const taskData: NewTaskData = {
        title: generatedData.title,
        description: generatedData.description,
        priority: generatedData.priority,
        columnId: project.board.columnOrder[0], 
        dueDate: generatedData.dueDate,
    };

    const newTask = await api.data.addTask(taskData, currentUser.id);
    if (newTask) {
      await api.data.moveTask(newTask.id, taskData.columnId, 1, currentUser.id);
    }
    await fetchData();
  }, [fetchData, state.projects, currentUser]);


  const deleteTask = useCallback(async (projectId: string, taskId: string, columnId: string) => {
    await api.data.deleteTask(taskId);
    await fetchData();
  }, [fetchData]);

  const addColumn = useCallback(async (projectId: string, title: string) => {
      await api.data.addColumn(projectId, title);
      await fetchData();
  }, [fetchData]);

  const deleteColumn = useCallback(async (projectId: string, columnId: string) => {
    await api.data.deleteColumn(columnId);
    await fetchData();
  }, [fetchData]);

  const addProject = useCallback(async (name: string, description: string, creatorId: string) => {
    await api.data.addProject(name, description, creatorId);
    await fetchData();
  }, [fetchData]);

  const addProjectFromPlan = useCallback(async (plan: AiGeneratedProjectPlan) => {
    if (!currentUser) throw new Error("User must be logged in.");
    const newProject = await api.data.createProjectShell(plan.name, plan.description, currentUser.id);

    for (const col of plan.columns) {
        const newColumn = await api.data.addColumn(newProject.id, col.title);
        if (newColumn) {
            for (const task of col.tasks) {
                const taskData: NewTaskData = {
                    title: task.title,
                    description: task.description,
                    priority: task.priority,
                    columnId: newColumn.id,
                };
                const newTask = await api.data.addTask(taskData, currentUser.id);
                if (newTask && task.subtasks && task.subtasks.length > 0) {
                    await api.data.addSubtasks(newTask.id, task.subtasks, currentUser.id);
                }
            }
        }
    }
    await fetchData();
  }, [fetchData, currentUser]);

  const deleteProject = useCallback(async (projectId: string) => {
    await api.data.deleteProject(projectId);
    await fetchData();
  }, [fetchData]);

  const updateUserProfile = useCallback(async (updates: { name: string }) => {
    if (!userId) return;
    await api.auth.updateUserProfile(userId, updates);
    await fetchData();
  }, [fetchData, userId]);

  const updateProjectMembers = useCallback(async (projectId: string, memberIds: string[]) => {
      await api.data.updateProjectMembers(projectId, memberIds);
      await fetchData();
  }, [fetchData]);

  const sendChatMessage = useCallback(async (projectId: string, text: string, author: User) => {
    playSentSound();
    const tempId = `temp-${Date.now()}`;
    const optimisticMessage: ChatMessage = {
        id: tempId,
        text,
        author,
        createdAt: new Date().toISOString(),
    };

    setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project) return prevState;
        return {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    chatMessages: [...project.chatMessages, optimisticMessage]
                }
            }
        }
    });

    try {
        await api.data.sendChatMessage(projectId, text, author.id);
    } catch (error) {
        setState(prevState => {
            const project = prevState.projects[projectId];
            if (!project) return prevState;
            return {
                ...prevState,
                projects: {
                    ...prevState.projects,
                    [projectId]: { ...project, chatMessages: project.chatMessages.filter(m => m.id !== tempId) }
                }
            }
        });
    }
  }, []);

  const addProjectLink = useCallback(async (projectId: string, title: string, url: string, creatorId: string) => {
    await api.data.addProjectLink(projectId, title, url, creatorId);
    await fetchData();
  }, [fetchData]);

  const deleteProjectLink = useCallback(async (linkId: string) => {
      await api.data.deleteProjectLink(linkId);
      await fetchData();
  }, [fetchData]);

  const addBug = useCallback(async (projectId: string, bugData: { title: string, description: string, priority: TaskPriority }) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
    if (!project) return;
    const firstColumn = project.board.columns[project.board.columnOrder[0]];
    const initialStatus = firstColumn ? firstColumn.title : 'New';

    await api.data.addBug({
        ...bugData,
        projectId,
        status: initialStatus,
        reporterId: currentUser.id,
    });
    await fetchData();
  }, [fetchData, currentUser, state.projects]);

  const addBugsBatch = useCallback(async (projectId: string, parsedBugs: BugResponse[]) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
     if (!project) return;
    const firstColumn = project.board.columns[project.board.columnOrder[0]];
    const initialStatus = firstColumn ? firstColumn.title : 'New';

    if (parsedBugs.length > 0) {
        const bugsToCreate = parsedBugs.map(b => ({
            title: b.title,
            description: b.description,
            project_id: projectId, // FIX: Use database snake_case
            priority: TaskPriority.MEDIUM,
            status: initialStatus,
            reporter_id: currentUser.id, // FIX: Use database snake_case
        }));
        await api.data.addBugsBatch(bugsToCreate);
        await fetchData();
    }
  }, [fetchData, currentUser, state.projects]);

  const updateBug = useCallback(async (bugId: string, updates: Partial<Bug>) => {
    const { title, description, priority, status, assignee } = updates;
    await api.data.updateBug(bugId, {
        title,
        description,
        priority,
        status,
        assigneeId: assignee?.id ?? (assignee === undefined ? undefined : null), 
    });
    await fetchData();
  }, [fetchData]);

  const deleteBug = useCallback(async (bugId: string) => {
    await api.data.deleteBug(bugId);
    await fetchData();
  }, [fetchData]);

  const deleteBugsBatch = useCallback(async (bugIds: string[]) => {
    await api.data.deleteBugsBatch(bugIds);
    await fetchData();
  }, [fetchData]);

  const addSprint = useCallback(async (projectId: string, sprintData: Omit<Sprint, 'id' | 'projectId' | 'createdAt' | 'status' | 'isDefault'> & { isDefault?: boolean }): Promise<Sprint> => {
    const newSprint = await api.data.addSprint({ ...sprintData, projectId });
    await fetchData();
    return newSprint;
  }, [fetchData]);

  const updateSprint = useCallback(async (projectId: string, sprintId: string, updates: Partial<Sprint>) => {
    await api.data.updateSprint(sprintId, updates);
    await fetchData();
  }, [fetchData]);

  const deleteSprint = useCallback(async (projectId: string, sprintId: string) => {
    await api.data.deleteSprint(sprintId);
    await fetchData();
  }, [fetchData]);

  const bulkUpdateTaskSprint = useCallback(async (taskIds: string[], sprintId: string | null) => {
    await api.from('tasks').update({ sprint_id: sprintId }).in('id', taskIds);
  }, []);

  const completeSprint = useCallback(async (sprintId: string, moveToSprintId: string | null) => {
    await api.data.completeSprint(sprintId, moveToSprintId);
    await fetchData();
  }, [fetchData]);

  const addFilterSegment = useCallback(async (projectId: string, name: string, filters: FilterSegment['filters'], creatorId: string) => {
    await api.data.addFilterSegment(projectId, name, filters, creatorId);
    await fetchData();
  }, [fetchData]);

  const updateFilterSegment = async (segmentId: string, updates: { name?: string, filters?: FilterSegment['filters'] }) => {
    await api.data.updateFilterSegment(segmentId, updates);
    await fetchData();
  };

  const deleteFilterSegment = useCallback(async (segmentId: string) => {
    await api.data.deleteFilterSegment(segmentId);
    await fetchData();
  }, [fetchData]);


  return { state, loading, fetchData, onDragEnd, updateTask, addSubtasks, addComment, addTask, addAiTask, deleteTask, addColumn, deleteColumn, addProject, addProjectFromPlan, deleteProject, updateUserProfile, updateProjectMembers, sendChatMessage, addProjectLink, deleteProjectLink, addBug, updateBug, deleteBug, addBugsBatch, deleteBugsBatch, addTasksBatch, addSprint, updateSprint, deleteSprint, bulkUpdateTaskSprint, completeSprint, addFilterSegment, updateFilterSegment, deleteFilterSegment };
};

