  const tableTotalPages = Math.ceil(filteredTasksForTable.length / TABLE_ITEMS_PER_PAGE);
  const paginatedTasksForTable = filteredTasksForTable.slice(
    (tableCurrentPage - 1) * TABLE_ITEMS_PER_PAGE,
