    if (assigneeFilter.length > 0) count++;
    if (statusFilter.length > 0) count++;
    if (tagFilter.length > 0) count++;
    if (sprintFilter.length > 0) count++;
    if (startDate || endDate) count++;
    if (relativeTimeValue) count++;
    return count;
