                            </div>
                        </div>
                    </div>
                    <button onClick={() => setIsAiNexusOpen(false)} className="p-2.5 rounded-xl text-gray-500 hover:text-white hover:bg-white/5 transition-all">
                        <XIcon className="w-6 h-6" />
                    </button>
