export const DashboardPage: React.FC<DashboardPageProps> = ({ projects, users, currentUser, onlineUsers, onSelectProject, onCreateProject, onManageMembers, onShareProject, addProjectFromPlan }) => {
    const [view, setView] = useState<'grid' | 'list'>('grid');
    const [generatedPlan, setGeneratedPlan] = useState<AiGeneratedProjectPlan | null>(null);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const ITEMS_PER_PAGE = 8;

    const allTasks = useMemo(() => projects.flatMap(p => p.board?.tasks ? Object.values(p.board.tasks) : []), [projects]);

    const activeTasks = useMemo(() => {
        return projects.flatMap(p => {
            if (!p.board?.columns || !p.board?.tasks) return [];

            const columns = Object.values(p.board.columns) as Column[];
            const doneColumn = columns.find(c => c.title.toLowerCase() === 'done');
            const doneTaskIds = new Set(doneColumn?.taskIds || []);

            const tasks = Object.values(p.board.tasks) as Task[];
            return tasks.filter(t => !doneTaskIds.has(t.id));
        });
    }, [projects]);

    const greeting = useMemo(() => {
        const hour = new Date().getHours();
        if (hour < 12) return 'Morning';
        if (hour < 18) return 'Afternoon';
        return 'Evening';
    }, []);

    // Neural Affinity Sorting: prioritizes projects you last interacted with
    const sortedProjects = useMemo(() => {
        const affinityKey = `neural-affinity-${currentUser.id}`;
        let affinityMap: Record<string, number> = {};
        try {
            affinityMap = JSON.parse(localStorage.getItem(affinityKey) || '{}');
        } catch (e) {
            console.error("Affinity read error", e);
        }

        return [...projects].sort((a, b) => {
            const timeA = affinityMap[a.id] || new Date(a.createdAt).getTime();
            const timeB = affinityMap[b.id] || new Date(b.createdAt).getTime();
            return timeB - timeA;
        });
    }, [projects, currentUser.id]);

    const totalPages = Math.ceil(sortedProjects.length / ITEMS_PER_PAGE);
    const paginatedProjects = sortedProjects.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

    const handleFileProcessed = async (csvContent: string) => {
        setIsAiProcessing(true);
        try {
            const plan = await generateProjectFromCsv(csvContent);
            setGeneratedPlan(plan);
        } catch (err) {
            alert(`AI Error: ${err instanceof Error ? err.message : "An unknown error occurred."}`);
        } finally {
            setIsAiProcessing(false);
        }
    };

    return (
        <div className="max-w-[1500px] mx-auto space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <div className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-[9px] uppercase tracking-widest text-emerald-400 mb-2">
                        <SparklesIcon className="w-2.5 h-2.5" /> Mesh Online
                    </div>
                    <h2 className="text-2xl font-bold text-white tracking-tight">
                        {greeting}, <span className="text-gray-500">{currentUser.name.split(' ')[0]}</span>
                    </h2>
                    <p className="text-gray-500 text-xs mt-0.5">{activeTasks.length} pending tasks across {projects.length} nodes.</p>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={onCreateProject} className="px-5 py-2 bg-white text-black font-bold rounded-lg hover:scale-105 transition-all flex items-center gap-2 text-xs shadow-xl shadow-white/5">
                        <PlusIcon className="w-4 h-4" /> New Node
                    </button>
                    <button onClick={() => exportTasksToCsv(projects, users)} className="p-2.5 bg-white/5 border border-white/10 rounded-xl text-white hover:bg-white/10 transition-all">
                        <DownloadIcon className="w-4 h-4" />
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                <StatCard icon={<LayoutDashboardIcon />} label="Nodes" value={projects.length} trend="+2%" />
                <StatCard icon={<CheckSquareIcon />} label="Mesh Tasks" value={activeTasks.length} />
                <StatCard icon={<TrendingUpIcon />} label="Team Flux" value={`${onlineUsers.size}/${Object.keys(users).length}`} trend="Live" />
                <StatCard icon={<ClockIcon />} label="Latency" value="< 10ms" />
            </div>

            <div className="grid grid-cols-12 gap-6">
                <div className="col-span-12 lg:col-span-9 space-y-4">
                    <div className="flex justify-between items-center">
                        <h3 className="text-base font-bold text-white flex items-center gap-2">Project Canvas <span className="text-[10px] font-medium text-gray-600 bg-white/5 px-2 py-0.5 rounded-full">{projects.length}</span></h3>
                        <div className="flex items-center gap-1.5 p-1 bg-white/5 rounded-lg border border-white/5">
                            <button onClick={() => setView('grid')} className={`p-1.5 rounded-md transition-all ${view === 'grid' ? 'bg-white/10 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><GridIcon className="w-3.5 h-3.5"/></button>
                            <button onClick={() => setView('list')} className={`p-1.5 rounded-md transition-all ${view === 'list' ? 'bg-white/10 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}><ListIcon className="w-3.5 h-3.5"/></button>
                        </div>
                    </div>

                    <ProjectDropzone onFileProcessed={handleFileProcessed} isLoading={isAiProcessing} />

                    {projects.length === 0 ? (
                        <div className="py-16 text-center bg-[#131C1B]/40 rounded-xl border border-dashed border-white/5 backdrop-blur-sm">
                            <LayoutDashboardIcon className="mx-auto h-12 w-12 text-gray-700 mb-3" />
                            <h3 className="text-lg font-bold text-white">Mesh Empty</h3>
                            <button onClick={onCreateProject} className="mt-6 px-5 py-2 bg-white/10 border border-white/10 text-white font-bold rounded-lg hover:bg-white/20 transition-all text-xs">Initialize Workflow</button>
                        </div>
                    ) : view === 'grid' ? (
                        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-4">
                            {paginatedProjects.map((p, idx) => (
                                <div key={p.id} className="relative">
                                    {idx === 0 && currentPage === 1 && (
                                        <div className="absolute -top-2 -left-2 z-10 px-2 py-0.5 bg-emerald-500 text-black text-[8px] font-black uppercase tracking-widest rounded-md shadow-lg rotate-[-5deg] animate-bounce">
                                            Current Nexus
                                        </div>
                                    )}
                                    <ProjectCard project={p} users={users} onlineUsers={onlineUsers} onSelect={onSelectProject} onManageMembers={onManageMembers} onShare={() => onShareProject(p)} />
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="bg-[#131C1B]/80 rounded-xl border border-white/5 overflow-hidden shadow-2xl backdrop-blur-xl">
                             <div className="grid grid-cols-12 gap-4 items-center px-5 py-3 border-b border-white/5 bg-white/5 text-[9px] uppercase tracking-[0.2em] font-bold text-gray-500">
                                <div className="col-span-4">Project Mesh</div>
                                <div className="col-span-2">Sync</div>
                                <div className="col-span-2 text-center">Load</div>
                                <div className="col-span-2 text-right">Team</div>
                                <div className="col-span-2"></div>
                            </div>
                            {paginatedProjects.map(p => (
                                <ProjectListRow key={p.id} project={p} users={users} onlineUsers={onlineUsers} onSelect={onSelectProject} onManageMembers={onManageMembers} onShare={() => onShareProject(p)} />
                            ))}
                        </div>
                    )}

                    {totalPages > 1 && <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} itemsPerPage={ITEMS_PER_PAGE} totalItems={projects.length} />}
                </div>

                <div className="col-span-12 lg:col-span-3 space-y-4">
                    <MiniCalendar tasks={allTasks} />
                    <DeadlineTracker tasks={activeTasks} onTaskClick={(task) => {
                        const parentProj = projects.find(p => p.board?.tasks?.[task.id]);
                        if (parentProj) onSelectProject(parentProj.id);
                    }} />
                    <div className="p-4 rounded-xl bg-gradient-to-br from-emerald-500/10 to-violet-500/10 border border-white/10 shadow-2xl">
                        <h4 className="text-[9px] font-bold uppercase tracking-[0.2em] text-white/50 mb-2 flex items-center gap-1.5">
                             Intelligence <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-ping" />
                        </h4>
                        <p className="text-[10px] text-gray-400 leading-relaxed italic">
                            Analyzing velocity. Sync in 24h.
                        </p>
                    </div>
                </div>
            </div>

            {generatedPlan && <ProjectConfirmationModal plan={generatedPlan} onConfirm={async () => { await addProjectFromPlan(generatedPlan); setGeneratedPlan(null); }} onCancel={() => setGeneratedPlan(null)} />}
        </div>
    );
};

import { useState, useEffect, useCallback } from 'react';
import { DropResult } from 'react-beautiful-dnd';
import { AppState, Task, NewTaskData, User, ChatMessage, AiGeneratedProjectPlan, Bug, TaskPriority, Subtask, AiGeneratedTaskFromFile, Sprint, FilterSegment, BugResponse } from '../types';
import { api } from '../services/api';
import { generateTaskFromPrompt } from '../services/geminiService';
import { Session } from '@supabase/supabase-js';
import { playSentSound } from '../utils/sound';

const initialState: AppState = {
  projects: {},
  users: {},
  projectOrder: [],
};

export const useAppState = (session: Session | null, currentUser: User | null, activeProjectId?: string | null) => {
  const [state, setState] = useState<AppState>(initialState);
  const [loading, setLoading] = useState(true);
  const userId = session?.user?.id;

  // Track project access telemetry
  useEffect(() => {
    if (activeProjectId) {
      const affinityKey = `neural-affinity-${userId}`;
      try {
        const affinityMap = JSON.parse(localStorage.getItem(affinityKey) || '{}');
        affinityMap[activeProjectId] = Date.now();
        localStorage.setItem(affinityKey, JSON.stringify(affinityMap));
      } catch (e) {
        console.warn("Affinity telemetry failed", e);
      }
    }
  }, [activeProjectId, userId]);

  const fetchData = useCallback(async (isInitial = false) => {
    if (!userId) {
      setState(initialState);
      setLoading(true);
      return;
    }

    if (isInitial) setLoading(true);

    try {
        const freshState = await api.data.fetchInitialData(userId);
        const cacheKey = `gemini-board-cache-${userId}`;

        try {
            localStorage.setItem(cacheKey, JSON.stringify(freshState));
        } catch (e) {
            console.warn("Could not save state to cache:", e);
        }

        setState(freshState);
    } catch (error) {
        console.error("An error occurred while fetching app data:", error);
    } finally {
        setLoading(false);
    }
  }, [userId]);

  useEffect(() => {
    if (!userId) {
      setState(initialState);
      setLoading(true);
      return;
    }

    const cacheKey = `gemini-board-cache-${userId}`;
    const cachedStateJSON = localStorage.getItem(cacheKey);
    if (cachedStateJSON) {
      try {
        setState(JSON.parse(cachedStateJSON));
        setLoading(false); 
      } catch (e) {
        console.warn("Failed to parse cached state, clearing it.", e);
        localStorage.removeItem(cacheKey);
      }
    }

    fetchData(Object.keys(state.projects).length === 0);

  }, [userId, fetchData]);

  useEffect(() => {
    if (!activeProjectId || !session || !userId) return;
    const cacheKey = `gemini-board-cache-${userId}`;

    const handleNewMessage = (payload: any) => {
      const newMessageData = payload.new;

      setState(prevState => {
        const author = prevState.users[newMessageData.author_id];
        if (!author) return prevState;

        const project = prevState.projects[activeProjectId];
        if (!project) return prevState;

        const finalMessage: ChatMessage = {
            id: newMessageData.id,
            text: newMessageData.text,
            createdAt: newMessageData.created_at,
            author: author,
        };

        const isSender = author.id === userId;
        let newMessages;

        if (isSender) {
          const optimisticIndex = project.chatMessages.findIndex(m => m.id.startsWith('temp-') && m.text === finalMessage.text);
          if (optimisticIndex > -1) {
            newMessages = [...project.chatMessages];
            newMessages[optimisticIndex] = finalMessage;
          } else {
            if (project.chatMessages.some(m => m.id === finalMessage.id)) return prevState;
            newMessages = [...project.chatMessages, finalMessage];
          }
        } else {
          if (project.chatMessages.some(m => m.id === finalMessage.id)) return prevState;
          newMessages = [...project.chatMessages, finalMessage];
        }

        const updatedState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [activeProjectId]: {
                    ...project,
                    chatMessages: newMessages.sort((a,b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()),
                }
            }
        };
        localStorage.setItem(cacheKey, JSON.stringify(updatedState));
        return updatedState;
      });
    };

    const subscription = api.data.subscribeToProjectChat(activeProjectId, handleNewMessage);
    return () => { subscription.unsubscribe(); };
  }, [activeProjectId, session, userId]);


  const onDragEnd = useCallback(async (projectId: string, result: DropResult) => {
    const { destination, source, draggableId, type } = result;
    if (!destination || !currentUser || !userId) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const project = state.projects[projectId];
    if (!project) return;
    const cacheKey = `gemini-board-cache-${userId}`;

    if (type === 'column') {
        const newColumnOrder = Array.from(project.board.columnOrder) as string[];
        newColumnOrder.splice(source.index, 1);
        newColumnOrder.splice(destination.index, 0, draggableId);

        setState(prevState => {
            const updatedState = {
                ...prevState,
                projects: {
                    ...prevState.projects,
                    [projectId]: {
                        ...prevState.projects[projectId],
                        board: { ...prevState.projects[projectId].board, columnOrder: newColumnOrder }
                    }
                }
            };
            localStorage.setItem(cacheKey, JSON.stringify(updatedState));
            return updatedState;
        });

        try {
            await api.data.updateColumnOrder(projectId, newColumnOrder);
        } catch (error) {
            await fetchData();
        }
        return;
    }

    const startCol = project.board.columns[source.droppableId];
    const endCol = project.board.columns[destination.droppableId];
    if (!startCol || !endCol) return;

    const newStartTaskIds = Array.from(startCol.taskIds);
    newStartTaskIds.splice(source.index, 1);
    const newEndTaskIds = startCol.id === endCol.id ? newStartTaskIds : Array.from(endCol.taskIds);
    if (startCol.id !== endCol.id) {
        newEndTaskIds.splice(destination.index, 0, draggableId);
    } else {
        newStartTaskIds.splice(destination.index, 0, draggableId);
    }

    setState(prevState => {
      const updatedColumns = {
        ...prevState.projects[projectId].board.columns,
        [startCol.id]: { ...startCol, taskIds: newStartTaskIds },
        [endCol.id]: { ...endCol, taskIds: newEndTaskIds }
      };
      const updatedState = {
        ...prevState,
        projects: {
          ...prevState.projects,
          [projectId]: { ...prevState.projects[projectId], board: { ...prevState.projects[projectId].board, columns: updatedColumns } }
        }
      };
      localStorage.setItem(cacheKey, JSON.stringify(updatedState));
      return updatedState;
    });

    try {
        await api.data.moveTask(draggableId, destination.droppableId, destination.index + 1, currentUser.id);
    } catch (error) {
        await fetchData();
    }
  }, [state, currentUser, userId, fetchData]);

  const updateTask = useCallback(async (projectId: string, updatedTask: Task) => {
      if (!currentUser) return;
      await api.data.updateTask(updatedTask, currentUser.id, Object.values(state.users) as User[]);
      await fetchData();
  }, [fetchData, currentUser, state.users]);

  const addSubtasks = useCallback(async (projectId: string, taskId: string, newSubtasksData: Partial<Subtask>[], creatorId: string) => {
    await api.data.addSubtasks(taskId, newSubtasksData, creatorId);
    await fetchData();
  }, [fetchData]);


  const addComment = useCallback(async (projectId: string, taskId: string, commentText: string, author: User) => {
      await api.data.addComment(taskId, commentText, author.id);
      await fetchData();
  }, [fetchData]);

  const addTask = useCallback(async (projectId: string, taskData: NewTaskData, creatorId: string) => {
    const newTask = await api.data.addTask(taskData, creatorId);
    if (newTask && currentUser) {
      await api.data.moveTask(newTask.id, taskData.columnId, 1, currentUser.id);
    }
    await fetchData();
  }, [fetchData, currentUser]);

  const addTasksBatch = useCallback(async (projectId: string, tasksToCreate: AiGeneratedTaskFromFile[], sprintId: string | null) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
    if (!project) return;

    const columnMap = new Map<string, string>();
    for (const colId of project.board.columnOrder) {
        const col = project.board.columns[colId];
        if (col?.title) {
            columnMap.set(col.title.toLowerCase().trim(), col.id);
        }
    }

    const firstColumnId = project.board.columnOrder[0];

    const tasksData = tasksToCreate.map(task => {
        const statusKey = (task.status || '').toLowerCase().trim();
        return {
            title: task.title,
            description: task.description,
            priority: task.priority,
            column_id: columnMap.get(statusKey) || firstColumnId,
            creator_id: currentUser.id,
            sprint_id: sprintId, 
            tags: []
        };
    });

    if (tasksData.length > 0) {
        try {
            await api.data.addTasksBatch(tasksData);
            await fetchData();
        } catch (err) {
            console.error("Supabase Batch Transmission Failed:", err);
            alert("Neural mesh failed to transmit task array to database.");
        }
    }
  }, [fetchData, currentUser, state.projects]);

  const addAiTask = useCallback(async (projectId: string, prompt: string) => {
    if (!currentUser) throw new Error("User must be logged in to create a task.");
    const project = state.projects[projectId];
    if (!project || project.board.columnOrder.length === 0) throw new Error("Cannot add AI task to a project with no columns.");

    const generatedData = await generateTaskFromPrompt(prompt);
    const taskData: NewTaskData = {
        title: generatedData.title,
        description: generatedData.description,
        priority: generatedData.priority,
        columnId: project.board.columnOrder[0], 
        dueDate: generatedData.dueDate,
    };

    const newTask = await api.data.addTask(taskData, currentUser.id);
    if (newTask) {
      await api.data.moveTask(newTask.id, taskData.columnId, 1, currentUser.id);
    }
    await fetchData();
  }, [fetchData, state.projects, currentUser]);


  const deleteTask = useCallback(async (projectId: string, taskId: string, columnId: string) => {
    await api.data.deleteTask(taskId);
    await fetchData();
  }, [fetchData]);

  const addColumn = useCallback(async (projectId: string, title: string) => {
      await api.data.addColumn(projectId, title);
      await fetchData();
  }, [fetchData]);

  // FIX: api.from was incorrectly used. Switched to api.data.deleteColumn which uses the correct service layer architecture.
  const deleteColumn = useCallback(async (projectId: string, columnId: string) => {
    await api.data.deleteColumn(columnId);
    await fetchData();
  }, [fetchData]);

  const addProject = useCallback(async (name: string, description: string, creatorId: string) => {
    await api.data.addProject(name, description, creatorId);
    await fetchData();
  }, [fetchData]);

  const addProjectFromPlan = useCallback(async (plan: AiGeneratedProjectPlan) => {
    if (!currentUser) throw new Error("User must be logged in.");
    const newProject = await api.data.createProjectShell(plan.name, plan.description, currentUser.id);

    for (const col of plan.columns) {
        const newColumn = await api.data.addColumn(newProject.id, col.title);
        if (newColumn) {
            for (const task of col.tasks) {
                const taskData: NewTaskData = {
                    title: task.title,
                    description: task.description,
                    priority: task.priority,
                    columnId: newColumn.id,
                };
                const newTask = await api.data.addTask(taskData, currentUser.id);
                if (newTask && task.subtasks && task.subtasks.length > 0) {
                    await api.data.addSubtasks(newTask.id, task.subtasks, currentUser.id);
                }
            }
        }
    }
    await fetchData();
  }, [fetchData, currentUser]);

  const deleteProject = useCallback(async (projectId: string) => {
    await api.data.deleteProject(projectId);
    await fetchData();
  }, [fetchData]);

  const updateUserProfile = useCallback(async (updates: { name: string }) => {
    if (!userId) return;
    await api.auth.updateUserProfile(userId, updates);
    await fetchData();
  }, [fetchData, userId]);

  const updateProjectMembers = useCallback(async (projectId: string, memberIds: string[]) => {
      await api.data.updateProjectMembers(projectId, memberIds);
      await fetchData();
  }, [fetchData]);

  const sendChatMessage = useCallback(async (projectId: string, text: string, author: User) => {
    playSentSound();
    const tempId = `temp-${Date.now()}`;
    const optimisticMessage: ChatMessage = {
        id: tempId,
        text,
        author,
        createdAt: new Date().toISOString(),
    };

    setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project) return prevState;
        return {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    chatMessages: [...project.chatMessages, optimisticMessage]
                }
            }
        }
    });

    try {
        await api.data.sendChatMessage(projectId, text, author.id);
    } catch (error) {
        setState(prevState => {
            const project = prevState.projects[projectId];
            if (!project) return prevState;
            return {
                ...prevState,
                projects: {
                    ...prevState.projects,
                    [projectId]: { ...project, chatMessages: project.chatMessages.filter(m => m.id !== tempId) }
                }
            }
        });
    }
  }, []);

  const addProjectLink = useCallback(async (projectId: string, title: string, url: string, creatorId: string) => {
    await api.data.addProjectLink(projectId, title, url, creatorId);
    await fetchData();
  }, [fetchData]);

  const deleteProjectLink = useCallback(async (linkId: string) => {
      await api.data.deleteProjectLink(linkId);
      await fetchData();
  }, [fetchData]);

  const addBug = useCallback(async (projectId: string, bugData: { title: string, description: string, priority: TaskPriority }) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
    if (!project) return;
    const firstColumn = project.board.columns[project.board.columnOrder[0]];
    const initialStatus = firstColumn ? firstColumn.title : 'New';

    await api.data.addBug({
        ...bugData,
        projectId,
        status: initialStatus,
        reporterId: currentUser.id,
    });
    await fetchData();
  }, [fetchData, currentUser, state.projects]);

  const addBugsBatch = useCallback(async (projectId: string, parsedBugs: BugResponse[]) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
     if (!project) return;
    const firstColumn = project.board.columns[project.board.columnOrder[0]];
    const initialStatus = firstColumn ? firstColumn.title : 'New';

    if (parsedBugs.length > 0) {
        const bugsToCreate = parsedBugs.map(b => ({
            title: b.title,
            description: b.description,
            project_id: projectId, // Ensure snake_case for DB
            priority: TaskPriority.MEDIUM,
            status: initialStatus,
            reporter_id: currentUser.id, // Ensure snake_case for DB
        }));
        await api.data.addBugsBatch(bugsToCreate);
        await fetchData();
    }
  }, [fetchData, currentUser, state.projects]);

  const updateBug = useCallback(async (bugId: string, updates: Partial<Bug>) => {
    const { title, description, priority, status, assignee } = updates;
    await api.data.updateBug(bugId, {
        title,
        description,
        priority,
        status,
        assigneeId: assignee?.id ?? (assignee === undefined ? undefined : null), 
    });
    await fetchData();
  }, [fetchData]);

  const deleteBug = useCallback(async (bugId: string) => {
    await api.data.deleteBug(bugId);
    await fetchData();
  }, [fetchData]);

  const deleteBugsBatch = useCallback(async (bugIds: string[]) => {
    await api.data.deleteBugsBatch(bugIds);
    await fetchData();
  }, [fetchData]);

  const addSprint = useCallback(async (projectId: string, sprintData: Omit<Sprint, 'id' | 'projectId' | 'createdAt' | 'status' | 'isDefault'> & { isDefault?: boolean }): Promise<Sprint> => {
    const newSprint = await api.data.addSprint({ ...sprintData, projectId });
    await fetchData();
    return newSprint;
  }, [fetchData]);

  const updateSprint = useCallback(async (projectId: string, sprintId: string, updates: Partial<Sprint>) => {
    await api.data.updateSprint(sprintId, updates);
    await fetchData();
  }, [fetchData]);

  const deleteSprint = useCallback(async (projectId: string, sprintId: string) => {
    await api.data.deleteSprint(sprintId);
    await fetchData();
  }, [fetchData]);

  const bulkUpdateTaskSprint = useCallback(async (taskIds: string[], sprintId: string | null) => {
    await api.data.bulkUpdateTaskSprint(taskIds, sprintId);
  }, []);

  const completeSprint = async (sprintId: string, moveToSprintId: string | null) => {
    await api.data.completeSprint(sprintId, moveToSprintId);
    await fetchData();
  };

  const addFilterSegment = useCallback(async (projectId: string, name: string, filters: FilterSegment['filters'], creatorId: string) => {
    await api.data.addFilterSegment(projectId, name, filters, creatorId);
    await fetchData();
  }, [fetchData]);

  const updateFilterSegment = async (segmentId: string, updates: { name?: string, filters?: FilterSegment['filters'] }) => {
    await api.data.updateFilterSegment(segmentId, updates);
    await fetchData();
  };

  const deleteFilterSegment = useCallback(async (segmentId: string) => {
    await api.data.deleteFilterSegment(segmentId);
    await fetchData();
  }, [fetchData]);


