                                <ShieldCheckIcon className="w-4 h-4" />
                            </div>
                            <p className="text-xs text-blue-300 font-medium">
                                Protocol Restriction: Only the project creator can initialize new invite nodes. You may propogate existing active tokens.
                            </p>
