const SelectHeadersModal: React.FC<{
  isOpen: boolean;
  headers: string[];
  onClose: () => void;
  onConfirm: (selected: string[]) => void;
}> = ({ isOpen, headers, onClose, onConfirm }) => {
  const [selected, setSelected] = useState<string[]>([]);
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
      <div className="bg-[#131C1B] border border-gray-800 rounded-xl p-6 max-w-sm w-full shadow-2xl">
        <h2 className="text-white font-bold text-lg mb-4">Select Context Headers</h2>
        <div className="max-h-60 overflow-y-auto custom-scrollbar mb-6 space-y-2">
          {headers.map(h => (
            <label key={h} className="flex items-center gap-2 text-sm text-gray-300 cursor-pointer">
              <input type="checkbox" onChange={() => setSelected(prev => prev.includes(h) ? prev.filter(x => x !== h) : [...prev, h])} />
              {h}
            </label>
          ))}
