  );
};

export default App;

import { useState, useEffect, useCallback } from 'react';
import { DropResult } from 'react-beautiful-dnd';
import { AppState, Task, NewTaskData, User, ChatMessage, AiGeneratedProjectPlan, Bug, TaskPriority, Subtask, AiGeneratedTaskFromFile, Sprint, FilterSegment, BugResponse, Project } from '../types';
import { api } from '../services/api';
import { generateTaskFromPrompt } from '../services/geminiService';
import { Session } from '@supabase/supabase-js';
import { playSentSound } from '../utils/sound';

const initialState: AppState = {
  projects: {},
  users: {},
  projectOrder: [],
};

export const useAppState = (session: Session | null, currentUser: User | null, activeProjectId?: string | null) => {
  const [state, setState] = useState<AppState>(initialState);
  const [loading, setLoading] = useState(true);
  const userId = session?.user?.id;

  const syncCache = (newState: AppState) => {
    if (!userId) return;
    const cacheKey = `gemini-board-cache-${userId}`;
    try {
        localStorage.setItem(cacheKey, JSON.stringify(newState));
    } catch (e) {
        console.warn("Could not sync cache:", e);
    }
  };

  const fetchData = useCallback(async (isInitial = false) => {
    if (!userId) {
      setState(initialState);
      setLoading(true);
      return;
    }

    if (isInitial) setLoading(true);

    try {
        const freshState = await api.data.fetchInitialData(userId);
        setState(prevState => {
            // Keep local comments/subtasks if they haven't synced yet, but prefer DB source of truth
            return freshState;
        });
        syncCache(freshState);
    } catch (error) {
        console.error("An error occurred while fetching app data:", error);
    } finally {
        setLoading(false);
    }
  }, [userId]);

  useEffect(() => {
    if (!userId) {
      setState(initialState);
      setLoading(true);
      return;
    }

    const cacheKey = `gemini-board-cache-${userId}`;
    const cachedStateJSON = localStorage.getItem(cacheKey);
    if (cachedStateJSON) {
      try {
        setState(JSON.parse(cachedStateJSON));
        setLoading(false); 
      } catch (e) {
        localStorage.removeItem(cacheKey);
      }
    }
    fetchData(Object.keys(state.projects).length === 0);
  }, [userId, fetchData]);

  useEffect(() => {
    if (!activeProjectId || !session || !userId) return;

    const handleNewMessage = (payload: any) => {
      const newMessageData = payload.new;
      setState(prevState => {
        const author = prevState.users[newMessageData.author_id];
        if (!author) return prevState;
        const project = prevState.projects[activeProjectId];
        if (!project) return prevState;

        const finalMessage: ChatMessage = {
            id: newMessageData.id,
            text: newMessageData.text,
            createdAt: newMessageData.created_at,
            author: author,
        };

        const isSender = author.id === userId;
        let newMessages;

        if (isSender) {
          const optimisticIndex = project.chatMessages.findIndex(m => m.id.startsWith('temp-') && m.text === finalMessage.text);
          if (optimisticIndex > -1) {
            newMessages = [...project.chatMessages];
            newMessages[optimisticIndex] = finalMessage;
          } else {
            if (project.chatMessages.some(m => m.id === finalMessage.id)) return prevState;
            newMessages = [...project.chatMessages, finalMessage];
          }
        } else {
          if (project.chatMessages.some(m => m.id === finalMessage.id)) return prevState;
          newMessages = [...project.chatMessages, finalMessage];
        }

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [activeProjectId]: {
                    ...project,
                    chatMessages: newMessages.sort((a,b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()),
                }
            }
        };
        syncCache(newState);
        return newState;
      });
    };

    const subscription = api.data.subscribeToProjectChat(activeProjectId, handleNewMessage);
    return () => { subscription.unsubscribe(); };
  }, [activeProjectId, session, userId]);


  const onDragEnd = useCallback(async (projectId: string, result: DropResult) => {
    const { destination, source, draggableId, type } = result;
    if (!destination || !currentUser || !userId) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const project = state.projects[projectId];
    if (!project) return;

    if (type === 'column') {
        const newColumnOrder = Array.from(project.board.columnOrder) as string[];
        newColumnOrder.splice(source.index, 1);
        newColumnOrder.splice(destination.index, 0, draggableId);

        setState(prevState => {
            const updatedState = {
                ...prevState,
                projects: {
                    ...prevState.projects,
                    [projectId]: {
                        ...prevState.projects[projectId],
                        board: { ...prevState.projects[projectId].board, columnOrder: newColumnOrder }
                    }
                }
            };
            syncCache(updatedState);
            return updatedState;
        });

        try {
            await api.data.updateColumnOrder(projectId, newColumnOrder);
        } catch (error) {
            await fetchData();
        }
        return;
    }

    const startCol = project.board.columns[source.droppableId];
    const endCol = project.board.columns[destination.droppableId];
    if (!startCol || !endCol) return;

    const newStartTaskIds = Array.from(startCol.taskIds);
    newStartTaskIds.splice(source.index, 1);
    const newEndTaskIds = startCol.id === endCol.id ? newStartTaskIds : Array.from(endCol.taskIds);
    if (startCol.id !== endCol.id) {
        newEndTaskIds.splice(destination.index, 0, draggableId);
    } else {
        newStartTaskIds.splice(destination.index, 0, draggableId);
    }

    setState(prevState => {
      const updatedColumns = {
        ...prevState.projects[projectId].board.columns,
        [startCol.id]: { ...startCol, taskIds: newStartTaskIds },
        [endCol.id]: { ...endCol, taskIds: newEndTaskIds }
      };
      const updatedState = {
        ...prevState,
        projects: {
          ...prevState.projects,
          [projectId]: { ...prevState.projects[projectId], board: { ...prevState.projects[projectId].board, columns: updatedColumns } }
        }
      };
      syncCache(updatedState);
      return updatedState;
    });

    try {
        await api.data.moveTask(draggableId, destination.droppableId, destination.index + 1, currentUser.id);
    } catch (error) {
        await fetchData();
    }
  }, [state, currentUser, userId, fetchData]);

  const updateTask = useCallback(async (projectId: string, updatedTask: Task) => {
      if (!currentUser) return;

      setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project) return prevState;

        const existingTask = project.board.tasks[updatedTask.id];
        // CRITICAL: Merge instead of overwrite to preserve history and comments
        const mergedTask = {
            ...existingTask,
            ...updatedTask,
            // Only use updated list if it's explicitly provided and non-empty
            subtasks: (updatedTask.subtasks?.length > 0) ? updatedTask.subtasks : (existingTask?.subtasks || []),
            comments: (updatedTask.comments?.length > 0) ? updatedTask.comments : (existingTask?.comments || []),
            history: (updatedTask.history?.length > 0) ? updatedTask.history : (existingTask?.history || []),
        };

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    board: {
                        ...project.board,
                        tasks: {
                            ...project.board.tasks,
                            [updatedTask.id]: mergedTask
                        }
                    }
                }
            }
        };
        syncCache(newState);
        return newState;
      });

      try {
        await api.data.updateTask(updatedTask, currentUser.id, Object.values(state.users) as User[]);
        // Optionally fetch history in background to see new entries
        setTimeout(() => fetchData(), 1000);
      } catch (err) {
        await fetchData();
      }
  }, [fetchData, currentUser, state.users]);

  const addSubtasks = useCallback(async (projectId: string, taskId: string, newSubtasksData: Partial<Subtask>[], creatorId: string) => {
    setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project || !project.board.tasks[taskId]) return prevState;

        const task = project.board.tasks[taskId];
        const tempSubtasks: Subtask[] = newSubtasksData.map((s, idx) => ({
            id: `temp-st-${Date.now()}-${idx}`,
            title: s.title || '',
            completed: !!s.completed,
            creatorId,
            createdAt: new Date().toISOString(),
            assigneeId: s.assigneeId
        }));

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    board: {
                        ...project.board,
                        tasks: {
                            ...project.board.tasks,
                            [taskId]: {
                                ...task,
                                subtasks: [...task.subtasks, ...tempSubtasks]
                            }
                        }
                    }
                }
            }
        };
        syncCache(newState);
        return newState;
    });

    try {
        await api.data.addSubtasks(taskId, newSubtasksData, creatorId);
        setTimeout(() => fetchData(), 500);
    } catch (err) {
        await fetchData();
    }
  }, [fetchData]);


  const addComment = useCallback(async (projectId: string, taskId: string, commentText: string, author: User) => {
      setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project || !project.board.tasks[taskId]) return prevState;

        const task = project.board.tasks[taskId];
        const newCommentObj = {
            id: `temp-comment-${Date.now()}`,
            text: commentText,
            author,
            createdAt: new Date().toISOString()
        };

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    board: {
                        ...project.board,
                        tasks: {
                            ...project.board.tasks,
                            [taskId]: {
                                ...task,
                                comments: [newCommentObj, ...task.comments]
                            }
                        }
                    }
                }
            }
        };
        syncCache(newState);
        return newState;
      });

      try {
        await api.data.addComment(taskId, commentText, author.id);
        setTimeout(() => fetchData(), 500);
      } catch (err) {
        await fetchData();
      }
  }, [fetchData]);

  const addTask = useCallback(async (projectId: string, taskData: NewTaskData, creatorId: string) => {
    const newTask = await api.data.addTask(taskData, creatorId);
    if (newTask && currentUser) {
      await api.data.moveTask(newTask.id, taskData.columnId, 1, currentUser.id);
    }
    await fetchData();
  }, [fetchData, currentUser]);

  const addTasksBatch = useCallback(async (projectId: string, tasksToCreate: AiGeneratedTaskFromFile[], sprintId: string | null) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
    if (!project) return;

    const columnMap = new Map<string, string>();
    for (const colId of project.board.columnOrder) {
        const col = project.board.columns[colId];
        if (col?.title) {
            columnMap.set(col.title.toLowerCase().trim(), col.id);
        }
    }

    const firstColumnId = project.board.columnOrder[0];
    const tasksData = tasksToCreate.map(task => {
        const statusKey = (task.status || '').toLowerCase().trim();
        return {
            title: task.title,
            description: task.description,
            priority: task.priority,
            column_id: columnMap.get(statusKey) || firstColumnId,
            creator_id: currentUser.id,
            sprint_id: sprintId, 
            tags: []
        };
    });

    if (tasksData.length > 0) {
        try {
            await api.data.addTasksBatch(tasksData);
            await fetchData();
        } catch (err) {
            await fetchData();
        }
    }
  }, [fetchData, currentUser, state.projects]);

  const addAiTask = useCallback(async (projectId: string, prompt: string) => {
    if (!currentUser) throw new Error("User must be logged in to create a task.");
    const project = state.projects[projectId];
    if (!project || project.board.columnOrder.length === 0) throw new Error("Cannot add AI task to a project with no columns.");

    const generatedData = await generateTaskFromPrompt(prompt);
    const taskData: NewTaskData = {
        title: generatedData.title,
        description: generatedData.description,
        priority: generatedData.priority,
        columnId: project.board.columnOrder[0], 
        dueDate: generatedData.dueDate,
    };

    const newTask = await api.data.addTask(taskData, currentUser.id);
    if (newTask) {
      await api.data.moveTask(newTask.id, taskData.columnId, 1, currentUser.id);
    }
    await fetchData();
  }, [fetchData, state.projects, currentUser]);


  const deleteTask = useCallback(async (projectId: string, taskId: string, columnId: string) => {
    setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project) return prevState;

        const newTasks = { ...project.board.tasks };
        delete newTasks[taskId];

        const newColumns = { ...project.board.columns };
        if (newColumns[columnId]) {
            newColumns[columnId] = {
                ...newColumns[columnId],
                taskIds: newColumns[columnId].taskIds.filter(id => id !== taskId)
            };
        }

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    board: {
                        ...project.board,
                        tasks: newTasks,
                        columns: newColumns
                    }
                }
            }
        };
        syncCache(newState);
        return newState;
    });

    try {
        await api.data.deleteTask(taskId);
    } catch (err) {
        await fetchData();
    }
  }, [fetchData]);

  const addColumn = useCallback(async (projectId: string, title: string) => {
      await api.data.addColumn(projectId, title);
      await fetchData();
  }, [fetchData]);

  const deleteColumn = useCallback(async (projectId: string, columnId: string) => {
    await api.data.deleteColumn(columnId);
    await fetchData();
  }, [fetchData]);

  const addProject = useCallback(async (name: string, description: string, creatorId: string) => {
    await api.data.addProject(name, description, creatorId);
    await fetchData();
  }, [fetchData]);

  const addProjectFromPlan = useCallback(async (plan: AiGeneratedProjectPlan) => {
    if (!currentUser) throw new Error("User must be logged in.");
    const newProject = await api.data.createProjectShell(plan.name, plan.description, currentUser.id);

    for (const col of plan.columns) {
        const newColumn = await api.data.addColumn(newProject.id, col.title);
        if (newColumn) {
            for (const task of col.tasks) {
                const taskData: NewTaskData = {
                    title: task.title,
                    description: task.description,
                    priority: task.priority,
                    columnId: newColumn.id,
                };
                const newTask = await api.data.addTask(taskData, currentUser.id);
                if (newTask && task.subtasks && task.subtasks.length > 0) {
                    await api.data.addSubtasks(newTask.id, task.subtasks, currentUser.id);
                }
            }
        }
    }
    await fetchData();
  }, [fetchData, currentUser]);

  const deleteProject = useCallback(async (projectId: string) => {
    await api.data.deleteProject(projectId);
    await fetchData();
  }, [fetchData]);

  const updateUserProfile = useCallback(async (updates: { name: string }) => {
    if (!userId) return;
    await api.auth.updateUserProfile(userId, updates);
    await fetchData();
  }, [fetchData, userId]);

  const updateProjectMembers = useCallback(async (projectId: string, memberIds: string[]) => {
      await api.data.updateProjectMembers(projectId, memberIds);
      await fetchData();
  }, [fetchData]);

  const sendChatMessage = useCallback(async (projectId: string, text: string, author: User) => {
    playSentSound();
    const tempId = `temp-${Date.now()}`;
    const optimisticMessage: ChatMessage = {
        id: tempId,
        text,
        author,
        createdAt: new Date().toISOString(),
    };

    setState(prevState => {
        const project = prevState.projects[projectId];
        if (!project) return prevState;
        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    chatMessages: [...project.chatMessages, optimisticMessage]
                }
            }
        };
        syncCache(newState);
        return newState;
    });

    try {
        await api.data.sendChatMessage(projectId, text, author.id);
    } catch (error) {
        setState(prevState => {
            const project = prevState.projects[projectId];
            if (!project) return prevState;
            return {
                ...prevState,
                projects: {
                    ...prevState.projects,
                    [projectId]: { ...project, chatMessages: project.chatMessages.filter(m => m.id !== tempId) }
                }
            }
        });
    }
  }, []);

  const addProjectLink = useCallback(async (projectId: string, title: string, url: string, creatorId: string) => {
    await api.data.addProjectLink(projectId, title, url, creatorId);
    await fetchData();
  }, [fetchData]);

  const deleteProjectLink = useCallback(async (linkId: string) => {
      await api.data.deleteProjectLink(linkId);
      await fetchData();
  }, [fetchData]);

  const addBug = useCallback(async (projectId: string, bugData: { title: string, description: string, priority: TaskPriority }) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
    if (!project) return;
    const firstColumn = project.board.columns[project.board.columnOrder[0]];
    const initialStatus = firstColumn ? firstColumn.title : 'New';

    await api.data.addBug({
        ...bugData,
        projectId,
        status: initialStatus,
        reporterId: currentUser.id,
    });
    await fetchData();
  }, [fetchData, currentUser, state.projects]);

  const addBugsBatch = useCallback(async (projectId: string, parsedBugs: BugResponse[]) => {
    if (!currentUser) return;
    const project = state.projects[projectId];
     if (!project) return;
    const firstColumn = project.board.columns[project.board.columnOrder[0]];
    const initialStatus = firstColumn ? firstColumn.title : 'New';

    if (parsedBugs.length > 0) {
        const bugsToCreate = parsedBugs.map(b => ({
            title: b.title,
            description: b.description,
            project_id: projectId, 
            priority: TaskPriority.MEDIUM,
            status: initialStatus,
            reporter_id: currentUser.id, 
        }));
        await api.data.addBugsBatch(bugsToCreate);
        await fetchData();
    }
  }, [fetchData, currentUser, state.projects]);

  const updateBug = useCallback(async (bugId: string, updates: Partial<Bug>) => {
    setState(prevState => {
        const projectEntry = (Object.entries(prevState.projects) as [string, Project][]).find(([_, p]) => p.bugs && p.bugs[bugId]);
        if (!projectEntry) return prevState;
        const [projectId, project] = projectEntry;

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...(project as Project),
                    bugs: {
                        ...(project as Project).bugs,
                        [bugId]: { ...(project as Project).bugs[bugId], ...updates }
                    }
                }
            }
        };
        syncCache(newState);
        return newState;
    });

    try {
        const { title, description, priority, status, assignee } = updates;
        await api.data.updateBug(bugId, {
            title,
            description,
            priority,
            status,
            assigneeId: assignee?.id ?? (assignee === undefined ? undefined : null), 
        });
    } catch (err) {
        await fetchData();
    }
  }, [fetchData]);

  const deleteBug = useCallback(async (bugId: string) => {
    await api.data.deleteBug(bugId);
    await fetchData();
  }, [fetchData]);

  const deleteBugsBatch = useCallback(async (bugIds: string[]) => {
    await api.data.deleteBugsBatch(bugIds);
    await fetchData();
  }, [fetchData]);

  const addSprint = useCallback(async (projectId: string, sprintData: Omit<Sprint, 'id' | 'projectId' | 'createdAt' | 'status' | 'isDefault'> & { isDefault?: boolean }): Promise<Sprint> => {
    const newSprint = await api.data.addSprint({ ...sprintData, projectId });
    await fetchData();
    return newSprint;
  }, [fetchData]);

  const updateSprint = useCallback(async (projectId: string, sprintId: string, updates: Partial<Sprint>) => {
    await api.data.updateSprint(sprintId, updates);
    await fetchData();
  }, [fetchData]);

  const deleteSprint = useCallback(async (projectId: string, sprintId: string) => {
    await api.data.deleteSprint(sprintId);
    await fetchData();
  }, [fetchData]);

  const bulkUpdateTaskSprint = useCallback(async (taskIds: string[], sprintId: string | null) => {
    await api.data.bulkUpdateTaskSprint(taskIds, sprintId);
    await fetchData();
  }, [fetchData]);

  const completeSprint = async (sprintId: string, moveToSprintId: string | null) => {
    await api.data.completeSprint(sprintId, moveToSprintId);
    await fetchData();
  };

  const addFilterSegment = useCallback(async (projectId: string, name: string, filters: FilterSegment['filters'], creatorId: string) => {
    await api.data.addFilterSegment(projectId, name, filters, creatorId);
    await fetchData();
  }, [fetchData]);

  const updateFilterSegment = async (segmentId: string, updates: { name?: string, filters?: FilterSegment['filters'] }) => {
    await api.data.updateFilterSegment(segmentId, updates);
    await fetchData();
  };

  const deleteFilterSegment = useCallback(async (segmentId: string) => {
    await api.data.deleteFilterSegment(segmentId);
    await fetchData();
  }, [fetchData]);


  return { state, loading, fetchData, onDragEnd, updateTask, addSubtasks, addComment, addTask, addAiTask, deleteTask, addColumn, deleteColumn, addProject, addProjectFromPlan, deleteProject, updateUserProfile, updateProjectMembers, sendChatMessage, addProjectLink, deleteProjectLink, addBug, updateBug, deleteBug, addBugsBatch, deleteBugsBatch, addTasksBatch, addSprint, updateSprint, deleteSprint, bulkUpdateTaskSprint, completeSprint, addFilterSegment, updateFilterSegment, deleteFilterSegment };
};

import React, { useState, useEffect, useCallback, FormEvent, useMemo, useRef } from 'react';
import { Task, Subtask, User, TaskPriority, Sprint } from '../types';
import { generateSubtasks as generateSubtasksFromApi } from '../services/geminiService';
import { XIcon, BotMessageSquareIcon, LoaderCircleIcon, SparklesIcon, CheckSquareIcon, MessageSquareIcon, PlusIcon, UserIcon, TagIcon, TrashIcon, HistoryIcon, CopyIcon, CheckIcon } from './Icons';
import { UserAvatar } from './UserAvatar';
import { useConfirmation } from '../App';
import { JsonSyntaxHighlighter } from './JsonSyntaxHighlighter';

interface TaskDetailsModalProps {
  task: Task;
  currentUser: User;
  users: User[];
  projectMembers: User[];
  allProjectTags: string[];
  sprints: Sprint[];
  onlineUsers: Set<string>;
  onClose: () => void;
  onUpdateTask: (task: Task) => Promise<void>;
  onAddSubtasks: (taskId: string, subtasks: Partial<Subtask>[]) => Promise<void>;
  onAddComment: (taskId: string, commentText: string) => Promise<void>;
}

type AIGenerationState = 'idle' | 'loading' | 'success' | 'error';

const CopyButton: React.FC<{ text: string; className?: string }> = ({ text, className }) => {
    const [copied, setCopied] = useState(false);

    const handleCopy = (e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();
        navigator.clipboard.writeText(text);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <button 
            onClick={handleCopy} 
            className={`p-1.5 rounded-md hover:bg-gray-700 transition-colors ${className}`}
            title="Copy to clipboard"
        >
            {copied ? <CheckIcon className="w-3.5 h-3.5 text-green-500" /> : <CopyIcon className="w-3.5 h-3.5 text-gray-400" />}
        </button>
    );
};

const isJsonContent = (text: string): boolean => {
    if (!text) return false;
    const trimmed = text.trim();
    if (!((trimmed.startsWith('{') && trimmed.endsWith('}')) || (trimmed.startsWith('[') && trimmed.endsWith(']')))) {
        return false;
    }
    try {
        JSON.parse(trimmed);
        return true;
    } catch {
        return false;
    }
};

const EditableField: React.FC<{value: string, onSave: (value: string) => void, isTextArea?: boolean, textClassName: string, inputClassName: string, placeholder?: string, type?: string }> = 
  ({ value, onSave, isTextArea = false, textClassName, inputClassName, placeholder, type = 'text' }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentValue, setCurrentValue] = useState(value);

  const handleSave = () => {
    if (currentValue !== value) {
        onSave(isTextArea ? currentValue.trim() : currentValue);
    }
    setIsEditing(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !isTextArea) {
        handleSave();
    } else if (e.key === 'Escape') {
        setCurrentValue(value);
        setIsEditing(false);
    }
  }

  useEffect(() => {
    setCurrentValue(value);
  }, [value]);


  if (isEditing) {
    const commonProps = {
        value: currentValue,
        onChange: (e: any) => setCurrentValue(e.target.value),
        onBlur: handleSave,
        onKeyDown: handleKeyDown,
        className: `w-full ${inputClassName}`,
        autoFocus: true,
        placeholder,
    }
    return isTextArea 
        ? <textarea {...commonProps} rows={4} /> 
        : <input type={type} {...commonProps} />;
  }

  if (isJsonContent(value)) {
      return (
          <div onClick={() => setIsEditing(true)} className="cursor-pointer group relative">
              <div className="absolute top-2 right-2 text-[10px] text-gray-500 opacity-0 group-hover:opacity-100 bg-[#0D1117] px-1 rounded border border-gray-800 z-10">Click to edit</div>
              <JsonSyntaxHighlighter data={value} />
          </div>
      );
  }

  return <div onClick={() => setIsEditing(true)} className={`min-h-[24px] ${textClassName}`}>{value || <span className="text-gray-500">{placeholder}</span>}</div>;
}

interface ActivitySectionProps {
    task: Task;
    onAddComment: (taskId: string, text: string) => Promise<void>;
    currentUser: User;
    projectMembers: User[];
    onlineUsers: Set<string>;
    users: User[];
}

const ActivitySection: React.FC<ActivitySectionProps> = ({ task, onAddComment, currentUser, projectMembers, onlineUsers, users }) => {
    const [newComment, setNewComment] = useState("");
    const [showMentions, setShowMentions] = useState(false);
    const [mentionSearch, setMentionSearch] = useState('');
    const [activeIndex, setActiveIndex] = useState(0);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    const filteredMembers = useMemo(() => {
        if (!mentionSearch) return projectMembers;
        return projectMembers.filter(member => 
            member.name.toLowerCase().includes(mentionSearch.toLowerCase())
        );
    }, [mentionSearch, projectMembers]);

    const handleCommentChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        const text = e.target.value;
        setNewComment(text);

        const cursorPos = e.target.selectionStart;
        const textToCursor = text.substring(0, cursorPos);

        const lastAt = textToCursor.lastIndexOf('@');
        if (lastAt === -1) {
            setShowMentions(false);
            return;
        }

        const potentialMention = textToCursor.substring(lastAt + 1);

        if (/\s/.test(potentialMention)) {
            setShowMentions(false);
            return;
        }

        setShowMentions(true);
        setMentionSearch(potentialMention);
        setActiveIndex(0);
    };

    const handleMentionSelect = (user: User) => {
        const text = newComment;
        const lastAt = text.lastIndexOf('@');

        if (lastAt !== -1) {
            const prefix = text.substring(0, lastAt);
            const suffix = text.substring(lastAt + 1 + mentionSearch.length);

            setNewComment(`${prefix}@${user.name} ${suffix.trimStart()}`);
            setShowMentions(false);
            textareaRef.current?.focus();
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (showMentions && filteredMembers.length > 0) {
            if (e.key === 'ArrowDown') { e.preventDefault(); setActiveIndex((prevIndex) => (prevIndex + 1) % filteredMembers.length); }
            else if (e.key === 'ArrowUp') { e.preventDefault(); setActiveIndex((prevIndex) => (prevIndex - 1 + filteredMembers.length) % filteredMembers.length); }
            else if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); handleMentionSelect(filteredMembers[activeIndex]); }
            else if (e.key === 'Escape') { e.preventDefault(); setShowMentions(false); }
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if(newComment.trim()){
            await onAddComment(task.id, newComment.trim());
            setNewComment("");
        }
    };

    const combinedFeed = useMemo(() => {
      const comments = (task.comments || []).map(c => ({ ...c, type: 'comment' as const }));
      const history = (task.history || []).map(h => ({ ...h, type: 'history' as const }));
      const feed = [...comments, ...history];
      feed.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
      return feed;
    }, [task.comments, task.history]);

    const renderWithMentions = (text: string) => {
        const escapeRegex = (str: string) => str.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
        const userNames = users.map(u => escapeRegex(u.name)).join('|');
        const regexParts = [];
        if (userNames) regexParts.push(`(@(${userNames})\\b)`);
        regexParts.push(`(https?:\\/\\/\\S+)`);
        const combinedRegex = new RegExp(regexParts.join('|'), 'g');
        const elements: React.ReactNode[] = [];
        let lastIndex = 0;
        let match;

        while ((match = combinedRegex.exec(text)) !== null) {
            let userName, url;
            if (userNames) { userName = match[2]; url = match[3]; } else { url = match[1]; }
            const fullMatch = match[0];
            const matchIndex = match.index;
            if (matchIndex > lastIndex) elements.push(text.substring(lastIndex, matchIndex));
            if (userName) elements.push(<strong key={matchIndex} className="bg-gray-500/30 text-white font-semibold rounded px-1 py-0.5">@{userName}</strong>);
            else if (url) elements.push(<a key={matchIndex} href={url} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:underline" onClick={(e) => e.stopPropagation()}>{url}</a>);
            lastIndex = matchIndex + fullMatch.length;
        }
        if (lastIndex < text.length) elements.push(text.substring(lastIndex));
        return <>{elements.length > 0 ? elements : text}</>;
    };

    return (
        <div>
            <h3 className="text-base font-semibold mb-3 flex items-center gap-2 text-white"><MessageSquareIcon className="w-5 h-5" /> Activity Feed</h3>
            <div className="flex items-start gap-3 mb-6">
                <UserAvatar user={currentUser} className="w-9 h-9 flex-shrink-0" isOnline={onlineUsers.has(currentUser.id)}/>
                <form onSubmit={handleSubmit} className="flex-grow">
                    <div className="relative">
                        <textarea 
                            ref={textareaRef}
                            value={newComment}
                            onChange={handleCommentChange}
                            onKeyDown={handleKeyDown}
                            placeholder="Add a comment... Use @ to mention"
                            className="w-full px-3 py-2 border border-gray-800 rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/50 bg-[#1C2326] text-white text-sm"
                            rows={2}
                        />
                        {showMentions && filteredMembers.length > 0 && (
                            <div className="absolute z-10 w-full bg-[#1C2326] border border-gray-700 rounded-md shadow-lg mt-1 max-h-48 overflow-y-auto custom-scrollbar">
                                <ul>
                                    {filteredMembers.map((user, index) => (
                                        <li 
                                            key={user.id}
                                            onClick={() => handleMentionSelect(user)}
                                            onMouseEnter={() => setActiveIndex(index)}
                                            className={`px-3 py-2 cursor-pointer flex items-center gap-2 ${index === activeIndex ? 'bg-gray-700' : 'hover:bg-gray-800/50'}`}
                                        >
                                            <UserAvatar user={user} className="w-6 h-6 text-xs flex-shrink-0" isOnline={onlineUsers.has(user.id)} />
                                            <span className="text-sm text-white">{user.name}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        )}
                    </div>
                    {newComment.trim() && !showMentions && (
                        <div className="flex justify-end mt-2">
                             <button type="submit" className="px-4 py-1.5 bg-emerald-500 text-black font-black uppercase tracking-widest rounded-lg text-[10px] hover:bg-emerald-400 transition-all shadow-xl shadow-emerald-500/10">
                                Post Update
                             </button>
                        </div>
                    )}
                </form>
            </div>
            <div className="space-y-6">
                {combinedFeed.length > 0 ? combinedFeed.map(item => {
                  const author = item.type === 'comment' ? item.author : item.user;
                  const isJson = item.type === 'comment' ? isJsonContent(item.text) : false;

                  return (
                    <div key={`${item.type}-${item.id}`} className="flex items-start gap-4 group">
                         {item.type === 'comment' ? (
                            <UserAvatar user={author} className="w-10 h-10 flex-shrink-0 ring-2 ring-white/5" isOnline={onlineUsers.has(author.id)}/>
                         ) : (
                            <div className="w-10 h-10 flex-shrink-0 flex items-center justify-center bg-white/5 rounded-full border border-white/5">
                                <HistoryIcon className="w-5 h-5 text-gray-500" />
                            </div>
                         )}
                         <div className="flex-grow min-w-0">
                            {item.type === 'comment' ? (
                                <>
                                    <div className="flex items-baseline gap-2 mb-1">
                                        <span className="font-bold text-sm text-white">{author.name}</span>
                                        <span className="text-[10px] font-mono text-gray-600 uppercase">{new Date(item.createdAt).toLocaleString()}</span>
                                    </div>
                                    <div className="relative">
                                        {isJson ? (
                                            <div className="mt-1">
                                                <JsonSyntaxHighlighter data={item.text} />
                                            </div>
                                        ) : (
                                            <div className="bg-[#1C2326] p-3 rounded-xl border border-white/5 relative overflow-hidden group/comment">
                                                <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500/20" />
                                                <p className="text-sm text-gray-300 leading-relaxed whitespace-pre-wrap">{renderWithMentions(item.text)}</p>
                                                <div className="absolute top-2 right-2 opacity-0 group-hover/comment:opacity-100 transition-opacity">
                                                    <CopyButton text={item.text} className="bg-black/40 hover:bg-black/60 p-1 rounded-lg" />
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </>
                            ) : (
                                <div className="py-1">
                                    <p className="text-xs text-gray-400 leading-relaxed">
                                        <span className="font-bold text-gray-300">{author.name}</span>
                                        {' '}
                                        <span className="text-gray-500 italic">{item.changeDescription}</span>
                                    </p>
                                    <span className="text-[9px] font-mono text-gray-700 uppercase block mt-0.5">{new Date(item.createdAt).toLocaleString()}</span>
                                </div>
                            )}
                         </div>
                    </div>
                  )
                }) : (
                    <div className="text-center py-10 opacity-40">
                         <MessageSquareIcon className="w-8 h-8 mx-auto mb-2 text-gray-600" />
                         <p className="text-xs font-bold uppercase tracking-widest text-gray-500">No activity logged in this node.</p>
                    </div>
                )}
            </div>
        </div>
    )
}


export const TaskDetailsModal: React.FC<TaskDetailsModalProps> = ({ task, currentUser, users, projectMembers, allProjectTags, sprints, onlineUsers, onClose, onUpdateTask, onAddSubtasks, onAddComment }) => {
  const [editedTask, setEditedTask] = useState<Task>(task);
  const [aiState, setAiState] = useState<AIGenerationState>('idle');
  const [aiError, setAiError] = useState<string | null>(null);
  const [newSubtaskTitle, setNewSubtaskTitle] = useState('');
  const [newSubtaskAssigneeId, setNewSubtaskAssigneeId] = useState('');
  const [newTag, setNewTag] = useState('');
  const [tagSuggestions, setTagSuggestions] = useState<string[]>([]);
  const [isTagInputFocused, setIsTagInputFocused] = useState(false);
  const [activeSuggestionIndex, setActiveSuggestionIndex] = useState(0);
  const requestConfirmation = useConfirmation();

  const taskCreator = users.find(u => u.id === task.creatorId);

  useEffect(() => {
    setEditedTask(task);
  }, [task]);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => { if (event.key === 'Escape') onClose(); };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  const handleUpdateField = (field: keyof Task, value: any) => {
    const updatedTask = { ...editedTask, [field]: value };
    setEditedTask(updatedTask);
    onUpdateTask(updatedTask);
  };

  const handleAssigneeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const assigneeId = e.target.value;
    const assignee = projectMembers.find(u => u.id === assigneeId);
    handleUpdateField('assignee', assignee);
  };

  const handlePriorityChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const priority = e.target.value as TaskPriority;
    handleUpdateField('priority', priority);
  };

  const handleSprintChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const sprintId = e.target.value;
    handleUpdateField('sprintId', sprintId || null);
  };

  const handleSubtaskToggle = (subtaskId: string) => {
    const updatedSubtasks = editedTask.subtasks.map(subtask => 
      subtask.id === subtaskId ? { ...subtask, completed: !subtask.completed } : subtask
    );
    handleUpdateField('subtasks', updatedSubtasks);
  };

  const handleSubtaskTitleChange = (subtaskId: string, newTitle: string) => {
    const updatedSubtasks = editedTask.subtasks.map(subtask => 
      subtask.id === subtaskId ? { ...subtask, title: newTitle } : subtask
    );
    handleUpdateField('subtasks', updatedSubtasks);
  };

  const handleGenerateSubtasks = useCallback(async () => {
    setAiState('loading');
    setAiError(null);
    try {
        const generated = await generateSubtasksFromApi(editedTask.title, editedTask.description);
        if (generated && generated.length > 0) {
            await onAddSubtasks(editedTask.id, generated.map(s => ({ title: s.title })));
        }
        setAiState('success');
    } catch(err) {
        setAiState('error');
        setAiError(err instanceof Error ? err.message : 'Neural link failure.');
    }
  }, [editedTask, onAddSubtasks]);

  const handleAddManualSubtask = async (e: FormEvent) => {
    e.preventDefault();
    if (newSubtaskTitle.trim()) {
        const newSubtask: Partial<Subtask> = { 
          title: newSubtaskTitle.trim(),
          assigneeId: newSubtaskAssigneeId || undefined,
        };
        await onAddSubtasks(editedTask.id, [newSubtask]);
        setNewSubtaskTitle('');
        setNewSubtaskAssigneeId('');
    }
  }

  const handleSubtaskAssigneeChange = (subtaskId: string, assigneeId: string) => {
    const newAssignee = projectMembers.find(u => u.id === assigneeId);
    const updatedSubtasks = editedTask.subtasks.map(subtask => {
        if (subtask.id === subtaskId) {
            return { 
                ...subtask, 
                assigneeId: newAssignee ? newAssignee.id : undefined,
                assignee: newAssignee || undefined,
            };
        }
        return subtask;
    });
    handleUpdateField('subtasks', updatedSubtasks);
  };

  const handleNewTagChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setNewTag(value);
    if (value) {
        const filtered = allProjectTags.filter(
            tag => tag.toLowerCase().includes(value.toLowerCase()) && !editedTask.tags.includes(tag)
        );
        setTagSuggestions(filtered);
        setActiveSuggestionIndex(0);
    } else {
        setTagSuggestions([]);
    }
  };

  const addTag = (tagToAdd: string) => {
    if (tagToAdd && !editedTask.tags.includes(tagToAdd)) {
        const newTags = [...new Set([...editedTask.tags, tagToAdd.trim()])];
        handleUpdateField('tags', newTags);
        setNewTag('');
        setTagSuggestions([]);
    }
  };

  const handleTagInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (isTagInputFocused && tagSuggestions.length > 0) {
        if (e.key === 'ArrowDown') { e.preventDefault(); setActiveSuggestionIndex(prev => (prev + 1) % tagSuggestions.length); return; }
        if (e.key === 'ArrowUp') { e.preventDefault(); setActiveSuggestionIndex(prev => (prev - 1 + tagSuggestions.length) % tagSuggestions.length); return; }
    }
    if (e.key === 'Enter') {
        e.preventDefault();
        let tagToAdd = newTag.trim();
        if (isTagInputFocused && tagSuggestions.length > 0 && tagSuggestions[activeSuggestionIndex]) {
            tagToAdd = tagSuggestions[activeSuggestionIndex];
        }
        addTag(tagToAdd);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
      const newTags = editedTask.tags.filter(tag => tag !== tagToRemove);
      handleUpdateField('tags', newTags);
  };

  const handleDeleteSubtask = (subtaskId: string) => {
    const subtaskToDelete = editedTask.subtasks.find(s => s.id === subtaskId);
    if (subtaskToDelete) {
      requestConfirmation({
        title: 'Delete Subtask',
        message: <>Remove subtask <strong>"{subtaskToDelete.title}"</strong>?</>,
        onConfirm: () => {
          const updatedSubtasks = editedTask.subtasks.filter(subtask => subtask.id !== subtaskId);
          handleUpdateField('subtasks', updatedSubtasks);
        },
        confirmText: 'Delete',
      });
    }
  };

  const completedSubtasks = (editedTask.subtasks || []).filter(st => st.completed).length;
  const totalSubtasks = (editedTask.subtasks || []).length;
  const progress = totalSubtasks > 0 ? (completedSubtasks / totalSubtasks) * 100 : 0;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-40 flex items-center justify-center p-4 animate-in fade-in duration-300" onClick={onClose}>
      <div className="bg-[#131C1B] rounded-2xl shadow-2xl w-full max-w-3xl max-h-[90vh] flex flex-col border border-white/5 relative overflow-hidden" onClick={(e) => e.stopPropagation()}>
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-emerald-500/20 to-transparent" />

        <header className="px-6 py-5 border-b border-white/5 flex justify-between items-center flex-shrink-0 bg-white/[0.02]">
            <div className="flex-grow mr-4 group flex items-center gap-3">
                <div className="p-2 rounded-xl bg-white/5 text-gray-500">
                    <CheckSquareIcon className="w-5 h-5" />
                </div>
                <div className="flex-grow">
                    <EditableField 
                        value={editedTask.title}
                        onSave={(newTitle) => handleUpdateField('title', newTitle)}
                        textClassName="text-xl font-black w-full cursor-pointer hover:text-emerald-400 rounded transition-colors text-white tracking-tight"
                        inputClassName="text-xl font-black p-1 rounded border-2 border-emerald-500/20 bg-black/40 focus:outline-none text-white w-full"
                        placeholder="Task Title"
