            newColumns[columnId] = {
                ...newColumns[columnId],
                taskIds: newColumns[columnId].taskIds.filter(id => id !== taskId)
            };
        }

        const newState = {
            ...prevState,
            projects: {
                ...prevState.projects,
                [projectId]: {
                    ...project,
                    board: {
                        ...project.board,
                        tasks: newTasks,
                        columns: newColumns
                    }
                }
            }
        };
        syncCache(newState);
        return newState;
