const getUserProfile = async (userId: string): Promise<User | null> => {
    const { data: userProfile, error } = await supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .single();
    if (error && error.code !== 'PGRST116') { 
        console.error("Error fetching user profile:", error.message || error);
        throw error; 
    }
    return userProfile as User;
};

const createUserProfile = async (supabaseUser: SupabaseUser): Promise<User> => {
    const name = supabaseUser.user_metadata?.name || supabaseUser.email?.split('@')[0] || 'New User';

    const { data, error } = await supabase
        .from('users')
        .insert({
            id: supabaseUser.id,
            name,
            role: UserRole.MEMBER, 
            avatar_url: '' 
        })
        .select()
        .single();

    if (error) {
        console.error("Error creating user profile:", error);
        throw error;
    }

    return data as User;
};

const updateUserProfile = async (userId: string, updates: { name: string }): Promise<User> => {
    const { data, error } = await supabase
        .from('users')
        .update(updates)
        .eq('id', userId)
        .select()
        .single();
    if (error) {
        console.error("Error updating user profile:", error.message || error);
        throw error;
    }
    return data as User;
};

